<?php
namespace Tests\Unit\Domain\Inventory;
use App\Domain\Inventory\Capacity\InventorySlotCalculator;use InvalidArgumentException;use PHPUnit\Framework\TestCase;
class InventorySlotCalculatorTest extends TestCase{/** @dataProvider boundaries */public function test_integer_boundaries($quantity,$expected){$result=(new InventorySlotCalculator())->calculate([['item_id'=>1,'quantity'=>$quantity,'max_stack'=>99]]);$this->assertSame($expected,$result->slots());}public function boundaries(){return[[0,0],[1,1],[99,1],[100,2],[198,2],[199,3]];}public function test_non_stackable_and_aggregation(){ $result=(new InventorySlotCalculator())->calculate([['item_id'=>8,'quantity'=>50,'max_stack'=>99],['item_id'=>8,'quantity'=>60,'max_stack'=>99],['item_id'=>9,'quantity'=>2,'max_stack'=>1]]);$this->assertSame(4,$result->slots());$this->assertSame(110,$result->quantities()[8]);}public function test_null_is_rejected(){ $this->expectException(InvalidArgumentException::class);(new InventorySlotCalculator())->calculate([['item_id'=>1,'quantity'=>1,'max_stack'=>null]]);}}
